INSERT INTO news_articles (id, slug, image, category, date, gallery, content, created_at, updated_at) VALUES
('news-1', 'gold-medal-international-science-olympiad', 'https://images.unsplash.com/photo-1524178232363-1fb2b075b655?q=80&w=2070&auto=format&fit=crop', 'Prestasi', '2026-05-15', '["https://images.unsplash.com/photo-1562774053-701939374585?q=80&w=2086&auto=format&fit=crop"]', '{"title":"Siswa Ar-Rahman Raih Emas di Olimpiade Sains Internasional","excerpt":"Siswa berbakat kami membawa pulang 3 medali emas dari Olimpiade Sains Pemuda Internasional di London, bersaing dengan 500+ peserta dari 40 negara.","content":"Pesantren Ar-Rahman terus menorehkan prestasi di kancah internasional setelah tiga siswa kami meraih medali emas di Olimpiade Sains Pemuda Internasional (IYSO) yang bergengsi di London, Inggris.\n\nKompetisi yang diikuti lebih dari 500 siswa dari 40 negara ini menguji peserta dalam bidang fisika, kimia, dan biologi melalui ujian teoritis dan praktik yang ketat.\n\nPeraih medali emas kami \u2014 Ahmad Rizki (Fisika), Siti Nurhaliza (Kimia), dan Muhammad Farhan (Biologi) \u2014 menunjukkan pengetahuan dan keterampilan pemecahan masalah yang luar biasa selama kompetisi seminggu penuh.\n\n\"Persiapannya sangat intens, tetapi guru-guru kami di Ar-Rahman memberikan dukungan yang luar biasa,\" kata Ahmad Rizki. \"Lab robotik dan fasilitas sains sangat membantu kami berlatih secara langsung.\"\n\nPimpinan Pesantren, KH. Ahmad Ziyad Khairy, menyatakan kebanggaannya: \"Prestasi ini membuktikan bahwa integrasi nilai-nilai Al-Quran dengan pendidikan sains modern menghasilkan lulusan yang kompetitif secara global.\"\n\nPara pemenang menerima medali mereka dalam upacara yang dihadiri oleh pemimpin pendidikan dari seluruh dunia, dengan duta besar Indonesia untuk Inggris yang menyerahkan penghargaan.","author":"Tim Media Ar-Rahman"}', NOW(3), NOW(3)),
('news-2', 'annual-cultural-festival-2026', 'https://images.unsplash.com/photo-1517457373958-b7bdd4587205?q=80&w=2069&auto=format&fit=crop', 'Acara', '2026-04-28', '["https://images.unsplash.com/photo-1540575467063-178a50c2df87?q=80&w=2070&auto=format&fit=crop"]', '{"title":"Festival Budaya Tahunan 2026: Perayaan Spektakuler","excerpt":"Ribuan orang berkumpul untuk festival tahunan kami yang menampilkan pertunjukan budaya, pameran seni, dan bazar megah yang menampilkan bakat siswa.","content":"Festival Budaya Tahunan Ar-Rahman 2026 sukses besar, menarik ribuan pengunjung dari seluruh wilayah Jabodetabek ke pesantren kami di Bekasi.\n\nFestival tahun ini dengan tema \\"Unity in Diversity\\" menampilkan berbagai pertunjukan yang mengesankan termasuk tarian tradisional dari seluruh nusantara, peragaan busana yang menonjolkan modest fashion, dan produksi teater oleh siswa Akademi Kepemimpinan kami.\n\nPameran seni menampilkan lebih dari 200 karya siswa, mulai dari kaligrafi dan lukisan hingga seni digital dan fotografi. Pengunjung sangat terkesan dengan pameran seni yang dihasilkan AI yang dibuat oleh siswa program Teknologi Digital kami.\n\nSorotan acara adalah bazar besar, di mana siswa menunjukkan keterampilan kewirausahaan mereka dengan menjual produk mulai dari kerajinan tangan hingga gadget teknologi yang mereka kembangkan sendiri.\n\n\"Kami ingin menunjukkan bahwa pendidikan Islam dan ekspresi kreatif berjalan beriringan,\" kata koordinator festival. \"Siswa kami membuktikan bahwa mereka bisa unggul dalam seni, budaya, dan kewirausahaan sambil mempertahankan nilai-nilai Islam mereka.\"\n\nFestival diakhiri dengan pertunjukan kembang api spektakuler dan lelang amal yang mengumpulkan dana lebih dari Rp 50 juta untuk beasiswa siswa kurang mampu.","author":"Tim Media Ar-Rahman"}', NOW(3), NOW(3)),
('news-3', 'open-enrollment-2026-2027', 'https://images.unsplash.com/photo-1486406146926-c627a92ad1ab?q=80&w=2071&auto=format&fit=crop', 'Penerimaan', '2026-04-01', NULL, '{"title":"Pendaftaran Dibuka Tahun Ajaran 2027/2028","excerpt":"Pendaftaran sekarang dibuka untuk tahun ajaran mendatang. Tempat terbatas di semua program. Pendaftaran awal sangat dianjurkan.","content":"Pesantren Tahfidz Qur''an dan Digital Arrahman dengan senang hati mengumumkan bahwa pendaftaran untuk tahun ajaran 2027/2028 sekarang dibuka.\n\nKami menyambut calon siswa dari tingkat SMP hingga SMA untuk bergabung dengan program-program prestisius kami. Sebagai pesantren premium yang secara unik menggabungkan hafalan Al-Quran dengan pendidikan teknologi digital mutakhir, kami menawarkan pengalaman pendidikan yang tak tertandingi.\n\nProgram Tersedia:\n- Program Tahfidz Al-Quran (SMP-SMA)\n- Program Teknologi Digital (SMP-SMA)\n- Program Bilingual (SMP-SMA)\n- Akademi Kepemimpinan (SMP-SMA)\n\nJadwal Pendaftaran:\n- Pendaftaran Awal: 1 April - 31 Mei 2027\n- Ujian Masuk: 15 Juni 2027\n- Wawancara: 20-25 Juni 2027\n- Pengumuman: 1 Juli 2027\n- Tahun Ajaran Baru: 15 Juli 2027\n\nKami mendorong orang tua untuk mendaftar lebih awal karena tempat terbatas. Beasiswa tersedia untuk siswa berprestasi.","author":"Kantor Penerimaan"}', NOW(3), NOW(3)),
('news-4', 'quran-competition-2026', 'https://images.unsplash.com/photo-1589182373726-e4f658ab50f0?q=80&w=2070&auto=format&fit=crop', 'Prestasi', '2026-03-20', NULL, '{"title":"Siswa Ar-Rahman Dominasi Kompetisi Quran Tingkat Provinsi","excerpt":"Siswa tahfidz kami meraih juara 1 di semua kategori pada Musabaqah Tilawatil Quran Tingkat Provinsi, menunjukkan penguasaan Al-Quran yang luar biasa.","content":"Siswa Pesantren Ar-Rahman mencapai prestasi luar biasa pada Musabaqah Tilawatil Quran (MTQ) Tingkat Provinsi 2026, meraih juara pertama di semua kategori kompetisi.\n\nPrestasi ini menunjukkan efektivitas kurikulum tahfidz terpadu kami, yang menggabungkan metode hafalan Al-Quran tradisional dengan pendekatan pedagogis modern.\n\nPemenang juara pertama:\n- Hafalan Quran (30 Juz): Muhammad Al-Fatih\n- Tilawah Al-Quran: Ahmad Syakir\n- Tafsir Al-Quran: Siti Aisyah\n- Kaligrafi Islam: Abdullah Hasan\n- Riset Al-Quran: Tim Ar-Rahman\n\n\"Program tahfidz kami dirancang tidak hanya untuk hafalan, tetapi untuk pemahaman dan penerapan yang mendalam,\" kata Ustadz Syamsul Huda, Kepala Program Tahfidz. \"Hasil ini mengkonfirmasi bahwa pendekatan kami berhasil.\"\n\nPara pemenang akan mewakili provinsi di kompetisi MTQ Nasional yang dijadwalkan pada Agustus 2026.","author":"Tim Media Ar-Rahman"}', NOW(3), NOW(3))
INSERT INTO programs (id, slug, icon, image, content, created_at, updated_at) VALUES
('prog-tahfidz', 'tahfidz', 'book-quran', 'https://images.unsplash.com/photo-1589182373726-e4f658ab50f0?q=80&w=2070&auto=format&fit=crop', '{"title":"Tahfidz Al-Quran","tagline":"Hafal Al-Quran dengan tajwid dan tafsir yang benar","desc":"Program hafalan Al-Quran komprehensif yang dirancang untuk melahirkan huffaz yang tidak hanya menghafal tetapi memahami dan mengamalkan Al-Quran.","duration":"6 Tahun","level":"SMP - SMA (Program 6 Tahun)","highlights":["Target hafalan 30 Juz","Sesi murajaah harian","Intensif Tajwid & Tashih","Studi Tafsir Al-Quran","Bahasa Arab Al-Quran","Tahsin & Qiraat Sab''ah"],"curriculum":["Tahfidz 30 Juz","Tajwid & Makharijul Huruf","Tafsir Al-Mishbah","Tata Bahasa Arab Quran","Hadits Arba''in","Fiqih Ibadah","Adab & Akhlak Islami","Imamah & Khitabah"],"outcomes":["Hafal 30 Juz Al-Quran","Menguasai tajwid secara teoritis & praktis","Mampu memimpin doa & shalat","Memahami tafsir ayat-ayat pilihan","Berakhlak mulia dengan nilai-nilai Quran"]}', NOW(3), NOW(3)),
('prog-digital', 'digital', 'laptop-code', 'https://images.unsplash.com/photo-1517694712202-14dd9538aa97?q=80&w=2070&auto=format&fit=crop', '{"title":"Teknologi Digital","tagline":"Kuasi coding, AI, dan inovasi digital","desc":"Program teknologi mutakhir yang mempersiapkan siswa untuk era digital. Dari dasar coding hingga kecerdasan buatan.","duration":"6 Tahun","level":"SMP - SMA (6 Year Program)","highlights":["Coding & Pemrograman","Kecerdasan Buatan (AI)","Robotik & IoT","Desain Digital","Keamanan Siber","Pengembangan Startup"],"curriculum":["Computational Thinking","Python & JavaScript","Web & Mobile Development","AI & Machine Learning","Teknik Robotik","Desain UI/UX","Pemasaran Digital","Kewirausahaan Teknologi"],"outcomes":["Menguasai minimal 2 bahasa pemrograman","Mampu membangun website & aplikasi","Memahami konsep AI & machine learning","Mampu merakit & memprogram robot","Siap bersaing di era digital global"]}', NOW(3), NOW(3)),
('prog-leadership', 'leadership', 'users', 'https://images.unsplash.com/photo-1517245386807-bb43f82c33c4?q=80&w=2070&auto=format&fit=crop', '{"title":"Akademi Kepemimpinan","tagline":"Bangun karakter dan pimpin dengan dampak","desc":"Program pengembangan kepemimpinan premium yang menumbuhkan kepercayaan diri, karakter, dan visi.","duration":"6 Tahun","level":"SMP - SMA (Program 6 Tahun)","highlights":["Pembangunan Karakter","Kepemimpinan Proyek","Perusahaan Sosial","Public Speaking","Pengabdian Masyarakat","Jejaring Global"],"curriculum":["Teori Kepemimpinan","Kecerdasan Emosional","Resolusi Konflik","Manajemen Proyek","Kewirausahaan Sosial","Keterampilan Negosiasi","Kepemimpinan Sipil","Kewarganegaraan Global"],"outcomes":["Memimpin tim & organisasi","Mengelola proyek sosial","Public speaking yang percaya diri","Jiwa wirausaha sosial","Jejaring global & kepemimpinan"]}', NOW(3), NOW(3))
