('test-1', 'Budi Santoso', 'Ahmad (Kelas 9)', 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?q=80&w=1974&auto=format&fit=crop', 1, '{"text":"Alhamdulillah, anak saya berkembang pesat baik dalam tahfidz maupun teknologi. Guru-gurunya sangat perhatian.","relation":"Orang Tua Siswa"}', NOW(3), NOW(3)),
('test-2', 'Siti Rahayu', 'Fatimah (Kelas 7)', 'https://images.unsplash.com/photo-1494790108377-be9c29b29330?q=80&w=1974&auto=format&fit=crop', 2, '{"text":"Pendidikan di Ar-Rahman benar-benar holistik. Anak saya tidak hanya pintar tapi juga berakhlak mulia.","relation":"Orang Tua Siswa"}', NOW(3), NOW(3)),
('test-3', 'Muhammad Fadil', 'Umar (Kelas 8)', 'https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?q=80&w=2070&auto=format&fit=crop', 3, '{"text":"Program digitalnya luar biasa. Anak saya sudah bisa membuat website sendiri di usia 13 tahun!","relation":"Orang Tua Siswa"}', NOW(3), NOW(3))
